const body = $json.body || $json;

function normalizeText(value) {
  return String(value || '')
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .trim();
}

const rawMessage = body.mensagem || body.message || body.text || '';
const msg = normalizeText(rawMessage);

let status = 'roteado';
let agente = 'Aninha';
let skill = 'vendas_condominios';
let produto = 'nao_classificado';
let prioridade = body.prioridade || 'media';
let proxima_acao = 'coletar_dados';
let precisa_avaliacao_tecnica = true;
let encaminhar_para = 'Humano';
let observacoes = [];

function hasAny(list) {
  return list.some(term => msg.includes(normalizeText(term)));
}

if (hasAny(['cisterna', 'caixa dagua', 'bomba', 'boia', 'nivel', 'recalque', 'painel'])) {
  agente = 'Diego';
  skill = hasAny(['painel', 'comando']) ? 'comandos_eletricos' : 'automacao_condominio';
  produto = 'DL Acqua / DL Commander';
  proxima_acao = 'agendar_avaliacao_tecnica';
  encaminhar_para = 'Orcamento';
} else if (hasAny(['portao', 'bluetooth', 'wireless', 'mobgate', 'abertura de acesso', 'porta de rolagem', 'controle remoto'])) {
  agente = 'Diego';
  skill = 'controle_acesso';
  produto = 'Gatekeeper';
  proxima_acao = 'agendar_avaliacao_tecnica';
  encaminhar_para = 'Orcamento';
} else if (hasAny(['condominio', 'sindico', 'portaria', 'morador', 'visitante', 'prestador', 'controle de acesso', 'condfy'])) {
  agente = 'Aninha';
  skill = 'vendas_condominios';
  produto = 'Fortress';
  proxima_acao = 'qualificar_lead';
  encaminhar_para = 'Orcamento';
} else if (hasAny(['camera', 'cftv', 'dvr', 'nvr', 'gravacao', 'camera offline', 'intelbras', 'hikvision'])) {
  agente = 'Diego';
  skill = 'suporte_cftv';
  produto = 'DL Guardião';
  proxima_acao = 'agendar_avaliacao_tecnica';
  encaminhar_para = 'Suporte';
} else if (hasAny(['eletrica', 'quadro', 'disjuntor', 'dr', 'dps', 'curto', 'circuito', 'iluminacao', 'energia'])) {
  agente = 'Diego';
  skill = 'suporte_eletrico';
  produto = 'DL Volt';
  proxima_acao = 'agendar_avaliacao_tecnica';
  encaminhar_para = 'Suporte';
} else if (hasAny(['rede', 'ip', 'vlan', 'switch', 'rack', 'wifi', 'fibra', 'cabeamento estruturado', 'internet'])) {
  agente = 'Diego';
  skill = 'infra_redes';
  produto = 'Infraestrutura de Redes';
  proxima_acao = 'agendar_avaliacao_tecnica';
  encaminhar_para = 'Suporte';
} else if (hasAny(['solar', 'inversor', 'placa', 'string', 'microinversor', 'bateria', 'on-grid', 'on grid', 'off-grid', 'off grid', 'hibrido'])) {
  agente = 'Diego';
  if (hasAny(['bateria', 'off-grid', 'off grid'])) {
    skill = 'solar_baterias';
  } else if (hasAny(['hibrido'])) {
    skill = 'solar_hibrida';
  } else {
    skill = 'solar_conexao_placas';
  }
  produto = 'DL EcoVolt';
  proxima_acao = 'agendar_avaliacao_tecnica';
  encaminhar_para = 'Orcamento';
} else if (hasAny(['post', 'postagem', 'instagram', 'facebook', 'tiktok', 'google meu negocio', 'legenda', 'conteudo', 'midia'])) {
  agente = 'SocialPilot';
  skill = 'postagem_social';
  produto = 'Marketing DL';
  proxima_acao = 'gerar_conteudo_pendente_aprovacao';
  precisa_avaliacao_tecnica = false;
  encaminhar_para = 'Marketing';
} else if (hasAny(['orcamento', 'proposta', 'valor', 'preco', 'material', 'compra', 'cotacao', 'suprimentos'])) {
  agente = 'Procurement';
  skill = 'orcamentacao_suprimentos';
  produto = 'Orçamento';
  proxima_acao = 'gerar_orcamento_pendente_aprovacao';
  encaminhar_para = 'Orcamento';
} else if (hasAny(['agenda', 'campo', 'equipe', 'execucao', 'material', 'rota', 'os', 'ordem de servico'])) {
  agente = 'Dispatcher';
  skill = 'field_ops_dispatcher';
  produto = 'Operação de Campo';
  proxima_acao = 'agendar_servico_campo';
  encaminhar_para = 'Operacional';
} else if (hasAny(['pos-venda', 'manutencao mensal', 'contrato', 'sla', 'recorrencia', 'acompanhamento', 'renovacao'])) {
  agente = 'Customer Success';
  skill = 'customer_success';
  produto = 'DL Partner';
  proxima_acao = 'revisar_sla_contrato';
  encaminhar_para = 'Atendimento';
} else if (hasAny(['banco', 'log', 'supabase', 'dados', 'duplicidade', 'crm', 'historico'])) {
  agente = 'DBA';
  skill = 'dba_supabase';
  produto = 'Dados / Supabase';
  proxima_acao = 'consultar_banco';
  precisa_avaliacao_tecnica = false;
  encaminhar_para = 'TI';
}

const termosProibidos = [
  'visita técnica',
  'visita tecnica',
  'diogo engenheiro',
  'engenheiro diogo',
  'canaleta plástica',
  'canaleta plastica',
  'hidráulica pura',
  'hidraulica pura'
];

const infracoes = termosProibidos.filter(t => msg.includes(normalizeText(t)));

if (infracoes.length > 0) {
  observacoes.push(`Bloqueio KILLCRITIC: Termos proibidos ignorados (${infracoes.join(', ')}).`);
}

observacoes.push('KILLCRITIC Activo: Usar Avaliação Técnica. Tecnólogo responsável em vez de Engenheiro. Sem hidráulica pura. Sem canaleta plástica. Separar escopo comercial (setup, SLA, peças, equipamentos). Priorizar DL Partner. Tudo requer aprovação humana.');

return [{
  json: {
    status,
    agente,
    skill,
    produto,
    prioridade,
    proxima_acao,
    precisa_avaliacao_tecnica,
    encaminhar_para,
    observacoes
  }
}];

